"using System;

namespace RohoFlow.Core.Site
{
    public class ManningPipeEngine
    {
        public struct PipeFlowOutput
        {
            public double CrossSectionalAreaSF { get; set; }
            public double HydraulicRadiusFt { get; set; }
            public double FlowVelocityFPS { get; set; }
            public double CapacityCFS { get; set; }
            public bool IsVelocityCompliant { get; set; }
        }

        /// <summary>
        /// Calculates full-flow pipe velocity and capacity using Manning's equation.
        /// </summary>
        public static PipeFlowOutput CalculateFullPipeFlow(
            double pipeDiameterIn,
            double slopePct,
            double roughnessN = 0.013) // Default PVC
        {
            double dFt = pipeDiameterIn / 12.0;
            double slopeVal = slopePct / 100.0;

            // Geometry metrics
            double area = (Math.PI * dFt * dFt) / 4.0;
            double radius = dFt / 4.0; // For full-flow, Hydraulic Radius R = D/4

            // Manning's Formula: V = (1.486 / n) * R^(2/3) * S^(1/2)
            double velocity = (1.486 / roughnessN) * Math.Pow(radius, 2.0 / 3.0) * Math.Sqrt(slopeVal);
            double capacity = velocity * area;

            // Newark flow velocity constraints (2.5 FPS to 10.0 FPS)
            bool isCompliant = velocity >= 2.5 && velocity <= 10.0;

            return new PipeFlowOutput
            {
                CrossSectionalAreaSF = area,
                HydraulicRadiusFt = radius,
                FlowVelocityFPS = velocity,
                CapacityCFS = capacity,
                IsVelocityCompliant = isCompliant
            };
        }
    }
}
