"using System;

namespace RohoFlow.Core.Site
{
    public class OrificeSizingEngine
    {
        public struct OrificeOutput
        {
            public double OrificeAreaSF { get; set; }
            public double DischargeCFS { get; set; }
        }

        /// <summary>
        /// Sizes flow control restrictor orifices using the standard discharge equation.
        /// </summary>
        public static OrificeOutput SizeOrifice(
            double diameterIn,
            double headFt,
            double dischargeCoefC = 0.60) // Standard sharp-edge orifice
        {
            double dFt = diameterIn / 12.0;
            double area = (Math.PI * dFt * dFt) / 4.0;

            // Orifice Discharge Q = C * A * sqrt(2 * g * h)
            double discharge = dischargeCoefC * area * Math.Sqrt(2.0 * 32.2 * headFt);

            return new OrificeOutput
            {
                OrificeAreaSF = area,
                DischargeCFS = discharge
            };
        }
    }
}
