namespace RohoFlow.Core.Site
{
    public class Gsr32RechargeEngine
    {
        public struct RechargeOutput
        {
            public double AnnualDeficitCF { get; set; }
            public double RechargeDeficitAcreInches { get; set; }
        }

        /// <summary>
        /// Calculates annual groundwater recharge deficit based on GSR-32 parameters.
        /// </summary>
        public static RechargeOutput CalculateRechargeDeficit(
            double imperviousProposedSF,
            double annualRechargeRateInches) // Soil-specific rate in inches per year
        {
            // Deficit Volume = Area (SF) * (Rate (Inches) / 12.0)
            double volCF = imperviousProposedSF * (annualRechargeRateInches / 12.0);

            // 1 Acre-inch = 3,630 cubic feet
            double acreIn = volCF / 3630.0;

            return new RechargeOutput
            {
                AnnualDeficitCF = volCF,
                RechargeDeficitAcreInches = acreIn
            };
        }
    }
}
