namespace RohoFlow.Revit
{
    [Transaction(TransactionMode.Manual)]
    public class StormwaterCalcCommand : IExternalCommand
    {
        public Result Execute(
            ExternalCommandData commandData,
            ref string message,
            ElementSet elements)
        {
            try
            {
                // 1. Get active UI Document and database Document
                UIDocument uiDoc = commandData.Application.ActiveUIDocument;
                if (uiDoc == null)
                {
                    message = "No active Revit project document is loaded.";
                    return Result.Failed;
                }
                Document doc = uiDoc.Document;

                // 2. Initialize MVVM View Model
                var viewModel = new UI.StormwaterCalcViewModel(doc);

                // 3. Load WPF View and bind Data Context
                var view = new UI.StormwaterCalcView();
                view.DataContext = viewModel;

                // 4. Present Modal Dialog to user
                bool? result = view.ShowDialog();

                return Result.Succeeded;
            }
            catch (Exception ex)
            {
                message = $"RohoFlow execution failed:\n{ex.Message}";
                return Result.Failed;
            }
        }
    }
}
