"using Autodesk.Revit.Attributes;
using Autodesk.Revit.DB;
using Autodesk.Revit.UI;
using System;
using System.Diagnostics;
using System.Windows.Interop;

namespace RohoFlow.Revit
{
    [Transaction(TransactionMode.Manual)]
    public class StormwaterCalcCommand : IExternalCommand
    {
        public Result Execute(
            ExternalCommandData commandData,
            ref string message,
            ElementSet elements)
        {
            try
            {
                // 1. Retrieve active UI active document from application
                UIDocument uiDoc = commandData.Application.ActiveUIDocument;
                if (uiDoc == null)
                {
                    message = "No active Revit project document is loaded.";
                    return Result.Failed;
                }

                // 2. Initialize MVVM View Model passing the active UIDocument
                var viewModel = new UI.StormwaterCalcViewModel(uiDoc);

                // 3. Load WPF View and bind Data Context
                var view = new UI.StormwaterCalcView();
                view.DataContext = viewModel;

                // 4. ELIMINATE WINDOW HUNG gotcha: Set owner handle to Revit main window process
                Process revitProcess = Process.GetCurrentProcess();
                IntPtr revitHandle = revitProcess.MainWindowHandle;

                WindowInteropHelper helper = new WindowInteropHelper(view);
                helper.Owner = revitHandle;

                // 5. Present Modal Dialog safely
                view.ShowDialog();

                return Result.Succeeded;
            }
            catch (Exception ex)
            {
                message = $"RohoFlow execution failed:\n{ex.Message}";
                return Result.Failed;
            }
        }
    }
}
