"using System;

namespace RohoFlow.Core.Site
{
    public class TR55Engine
    {
        public struct TR55Output
        {
            public double IaP { get; set; }
            public double Qu { get; set; } // Unit peak discharge (cfs/mi^2/in)
            public double PeakInflowCFS { get; set; }
            public double RequiredDetentionVolumeCF { get; set; }
        }

        /// <summary>
        /// Calculates unit peak discharge (qu) using SCS TR-55 Type III curve coefficients.
        /// </summary>
        public static double CalculateUnitPeakDischarge(double tcHours, double iaP)
        {
            if (tcHours <= 0) tcHours = 0.1; // Minimum Tc is 0.1 hours (6 min) in TR-55
            if (tcHours > 10.0) tcHours = 10.0; // Max Tc clamp for Graphical Method

            // TR-55 Type III coefficients for Ia/P ratios
            // Ia/P = 0.10
            double c0_10 = 2.4466, c1_10 = -0.19013, c2_10 = -0.11958;
            // Ia/P = 0.30
            double c0_30 = 2.23537, c1_30 = -0.37089, c2_30 = -0.07662;

            double c0, c1, c2;
            if (iaP <= 0.10)
            {
                c0 = c0_10; c1 = c1_10; c2 = c2_10;
            }
            else if (iaP >= 0.30)
            {
                c0 = c0_30; c1 = c1_30; c2 = c2_30;
            }
            else
            {
                // Linearly interpolate coefficients between Ia/P = 0.10 and 0.30
                double fraction = (iaP - 0.10) / 0.20;
                c0 = c0_10 + fraction * (c0_30 - c0_10);
                c1 = c1_10 + fraction * (c1_30 - c1_10);
                c2 = c2_10 + fraction * (c2_30 - c2_10);
            }

            double logTc = Math.Log10(tcHours);
            double logQu = c0 + c1 * logTc + c2 * logTc * logTc;
            return Math.Pow(10.0, logQu);
        }

