                double.TryParse(SeededProposedSFText, out double seeded);

                if (sourceProperty == nameof(BuildingProposedSFText) || 
                    sourceProperty == nameof(PavedOnSiteSFText) || 
                    sourceProperty == nameof(PavedOffSiteSFText) ||
                    sourceProperty == nameof(LotSFText))
                {
                    // Adjust Seeded/Pervious Area to match total lot
                    double targetSeeded = lot - bld - pavedOn - pavedOff;
                    if (targetSeeded < 0) targetSeeded = 0;
