"# Get the parent directory of this script
$ScriptDir = Split-Path -Parent $MyInvocation.MyCommand.Path
if ([string]::IsNullOrEmpty($ScriptDir)) {
    $ScriptDir = Get-Location
}

# The brain directory where Antigravity saves conversation folders
$BrainDir = "C:\Users\thoma\.gemini\antigravity\brain"

if (-not (Test-Path $BrainDir)) {
    Write-Error "Antigravity brain folder not found at: $BrainDir"
    exit 1
}

# Find the most recently modified conversation directory in the brain folder
$LatestConv = Get-ChildItem -Path $BrainDir -Directory | 
    Sort-Object LastWriteTime -Descending | 
    Select-Object -First 1

if ($null -eq $LatestConv) {
    Write-Error "No conversation directories found under: $BrainDir"
    exit 1
}

$ConvPath = $LatestConv.FullName
$ConvId = $LatestConv.Name

Write-Host "Found active conversation directory: $ConvId ($ConvPath)"

# Paths to copy
