$SourceImplPlan = Join-Path $ConvPath "implementation_plan.md"
$SourceWalkthrough = Join-Path $ConvPath "walkthrough.md"
$SourceTask = Join-Path $ConvPath "task.md"

# Copy files if they exist
if (Test-Path $SourceTranscript) {
    Copy-Item -Path $SourceTranscript -Destination (Join-Path $ScriptDir "transcript.jsonl") -Force
    Write-Host "Synced transcript.jsonl"
} else {
    Write-Warning "No transcript file found at: $SourceTranscript"
}

